public class DumbNo2Slash //this method take quadratic time 
{
    public static void main(String[] args)
    {
       // In s = new In("test0.txt");
        String name= StdIn.readString() ;
        String out = "";

        int n = name.length();
        int i = 1;
        char [] c = name.toCharArray();  
        while (i < n)
        {
            if ((c[i-1] == '/') && (c[i] == '/'))
            {
                for(int j = i+1; j < n; j++)
                    c[j-1] = c[j];
                    n--;
            }
        else i++;
        }

        for (int j = 0;j < c.length ; j++) {
            out += c[j];
        }


        StdOut.println(out);

        // code-end

        return;
    }
}

